// C++ class designed for Blueprint extension
UCLASS(Blueprintable)
class AMyActor : public AActor {
    GENERATED_BODY()
public:
    // Blueprint can call this
    UFUNCTION(BlueprintCallable, Category="Combat")
    void DealDamage(float Amount);

    // Blueprint must implement this
    UFUNCTION(BlueprintImplementableEvent, Category="Combat")
    void OnDamageTaken(float Amount);

    // C++ default + Blueprint can override
    UFUNCTION(BlueprintNativeEvent, Category="Combat")
    float CalculateArmor();
    virtual float CalculateArmor_Implementation();

    UPROPERTY(EditAnywhere, BlueprintReadWrite)
    float MaxHealth = 100.f;
};

// C++ event dispatcher exposed to Blueprint
DECLARE_DYNAMIC_MULTICAST_DELEGATE_OneParam(FOnHealthChanged, float, NewHealth);

UCLASS()
class AMyCharacter : public ACharacter {
    GENERATED_BODY()
public:
    UPROPERTY(BlueprintAssignable, Category="Events")
    FOnHealthChanged OnHealthChanged;

    void TakeDamage(float Amount) {
        Health -= Amount;
        OnHealthChanged.Broadcast(Health);  // All listeners are notified
    }
};

// C++ Blueprint Interface
UINTERFACE(MinimalAPI, Blueprintable)
class UInteractable : public UInterface {
    GENERATED_BODY()
};

class IInteractable {
    GENERATED_BODY()
public:
    UFUNCTION(BlueprintCallable, BlueprintNativeEvent, Category="Interaction")
    void Interact(AActor* Caller);
};

// Actor implementing it
class ADoor : public AActor, public IInteractable {
    virtual void Interact_Implementation(AActor* Caller) override {
        ToggleDoor();
    }
};
